class BaseTask:
    def __init__(self, title, status="open"):
        self.title = title
        self.status = status

from models.base_task import BaseTask

class BugTask(BaseTask):
    def __init__(self, title, severity, status="open"):
        super().__init__(title, status)
        self.severity = severity

    def label(self):
        return f"BUG: {self.title} ({self.severity}) [{self.status}]"

from models.base_task import BaseTask

class FeatureTask(BaseTask):
    def __init__(self, title, area, status="open"):
        super().__init__(title, status)
        self.area = area

    def label(self):
        return f"FEATURE: {self.title} ({self.area}) [{self.status}]"

